---@return Point
function Point.new(x, y, label__local)
    return setmetatable({ x = x, y = y, label = label__local }, Point)
end

---@return integer
function Point:distance_sq()
    return self.x * self.x + self.y * self.y
end

function Point:translate(dx, dy)
    self.x = self.x + dx
    self.y = self.y + dy
end

